import type { Identifier, RaRecord } from "ra-core";
import type { ComponentType } from "react";

import type {
  COMPANY_CREATED,
  CONTACT_CREATED,
  CONTACT_NOTE_CREATED,
  DEAL_CREATED,
  DEAL_NOTE_CREATED,
} from "./consts";

export type SignUpData = {
  email: string;
  password: string;
  first_name: string;
  last_name: string;
};

export type SalesFormData = {
  avatar?: string;
  email: string;
  password?: string;
  first_name: string;
  last_name: string;
  administrator: boolean;
  disabled: boolean;
};

export type Sale = {
  first_name: string;
  last_name: string;
  administrator: boolean;
  avatar?: RAFile;
  disabled?: boolean;
  user_id: string;

  /**
   * This is a copy of the user's email, to make it easier to handle by react admin
   * DO NOT UPDATE this field directly, it should be updated by the backend
   */
  email: string;

  /**
   * This is used by the fake rest provider to store the password
   * DO NOT USE this field in your code besides the fake rest provider
   * @deprecated
   */
  password?: string;
} & Pick<RaRecord, "id">;

export type LeadSource =
  | "outbound"
  | "referral"
  | "partner"
  | "manual"
  | "email_campaign"
  | "seo"
  | "other"
  | "unknown";

export type Company = {
  name: string;
  logo: RAFile;
  sector: string;
  size: 1 | 10 | 50 | 250 | 500;
  linkedin_url: string;
  website: string;
  phone_number: string;
  address: string;
  zipcode: string;
  city: string;
  state_abbr: string;
  sales_id?: Identifier;
  created_at: string;
  description: string;
  revenue: string;
  tax_identifier: string;
  country: string;
  context_links?: string[];
  nb_contacts?: number;
  nb_deals?: number;
  lead_source: LeadSource;
  stripe_customer_id?: string | null;
} & Pick<RaRecord, "id">;

export type EmailAndType = {
  email: string;
  type: "Work" | "Home" | "Other";
};

export type PhoneNumberAndType = {
  number: string;
  type: "Work" | "Home" | "Other";
};

export type Contact = {
  first_name: string;
  last_name: string;
  title: string;
  company_id?: Identifier | null;
  email_jsonb: EmailAndType[];
  avatar?: Partial<RAFile>;
  linkedin_url?: string | null;
  first_seen: string;
  last_seen: string;
  has_newsletter: boolean;
  tags: number[];
  gender: string;
  sales_id?: Identifier;
  status: string;
  background: string;
  phone_jsonb: PhoneNumberAndType[];
  nb_tasks?: number;
  nb_unread_emails?: number;
  company_name?: string;
  lead_source: LeadSource;
} & Pick<RaRecord, "id">;

export type ContactNote = {
  contact_id: Identifier;
  text: string;
  date: string;
  sales_id: Identifier;
  status: string;
  attachments?: AttachmentNote[];
} & Pick<RaRecord, "id">;

export type Deal = {
  name: string;
  company_id: Identifier;
  contact_ids: Identifier[];
  category: string;
  stage: string;
  description: string;
  amount: number;
  created_at: string;
  updated_at: string;
  archived_at?: string;
  expected_closing_date: string;
  sales_id: Identifier;
  index: number;
  lead_source: LeadSource;
} & Pick<RaRecord, "id">;

export type DealNote = {
  deal_id: Identifier;
  text: string;
  date: string;
  sales_id: Identifier;
  attachments?: AttachmentNote[];

  // This is defined for compatibility with `ContactNote`
  status?: undefined;
} & Pick<RaRecord, "id">;

export type Tag = {
  id: number;
  name: string;
  color: string;
};

export type Task = {
  contact_id: Identifier;
  type: string;
  text: string;
  due_date: string;
  done_date?: string | null;
  sales_id?: Identifier;
} & Pick<RaRecord, "id">;

export type ActivityCompanyCreated = {
  type: typeof COMPANY_CREATED;
  company_id: Identifier;
  company: Company;
  sales_id: Identifier;
  date: string;
} & Pick<RaRecord, "id">;

export type ActivityContactCreated = {
  type: typeof CONTACT_CREATED;
  company_id: Identifier;
  sales_id?: Identifier;
  contact: Contact;
  date: string;
} & Pick<RaRecord, "id">;

export type ActivityContactNoteCreated = {
  type: typeof CONTACT_NOTE_CREATED;
  sales_id?: Identifier;
  contactNote: ContactNote;
  date: string;
} & Pick<RaRecord, "id">;

export type ActivityDealCreated = {
  type: typeof DEAL_CREATED;
  company_id: Identifier;
  sales_id?: Identifier;
  deal: Deal;
  date: string;
};

export type ActivityDealNoteCreated = {
  type: typeof DEAL_NOTE_CREATED;
  sales_id?: Identifier;
  dealNote: DealNote;
  date: string;
};

export type Activity = RaRecord &
  (
    | ActivityCompanyCreated
    | ActivityContactCreated
    | ActivityContactNoteCreated
    | ActivityDealCreated
    | ActivityDealNoteCreated
  );

export type AppointmentSource = "phone_call" | "email_campaign" | "manual";
export type AppointmentStatus = "scheduled" | "completed" | "cancelled";

export type Appointment = {
  contact_id: Identifier | null;
  title: string;
  description: string | null;
  start_at: string;
  end_at: string;
  location: string | null;
  source: AppointmentSource;
  status: AppointmentStatus;
  sales_id: Identifier;
  created_at: string;
} & Pick<RaRecord, "id">;

export type EmailAccount = {
  email: string;
  imap_host: string;
  imap_port: number;
  smtp_host?: string | null;
  smtp_port: number;
  sales_id?: Identifier | null;
  is_active: boolean;
  skip_tls_verify: boolean;
  created_at: string;
} & Pick<RaRecord, "id">;

export type EmailMessage = {
  message_id: string;
  email_account_id: Identifier;
  folder: string;
  from_email: string;
  from_name: string | null;
  to_emails: { email: string; name: string | null }[] | null;
  cc_emails: { email: string; name: string | null }[] | null;
  subject: string | null;
  text_body: string | null;
  html_body: string | null;
  date: string;
  is_read: boolean;
  contact_id: Identifier | null;
  sales_id: Identifier | null;
  uid: number | null;
  created_at: string;
} & Pick<RaRecord, "id">;

export type UnreadEmail = {
  from_email: string;
  from_name: string | null;
  subject: string | null;
  date: string;
  contact_id: Identifier | null;
  sales_id: Identifier | null;
  email_account_id: Identifier;
  account_email: string;
  contact_first_name: string | null;
  contact_last_name: string | null;
} & Pick<RaRecord, "id">;

export type ContactRecording = {
  contact_id: Identifier;
  storage_path: string;
  duration_seconds: number;
  transcription: string | null;
  transcription_status: "pending" | "processing" | "completed" | "error";
  summary: string | null;
  email_advice: string | null;
  sms_advice: string | null;
  email_draft: string | null;
  sms_draft: string | null;
  sentiment: string | null;
  warmth_score: number | null;
  warmth_label: string | null;
  created_at: string;
  sales_id: Identifier;
} & Pick<RaRecord, "id">;

export interface RAFile {
  src: string;
  title: string;
  path?: string;
  rawFile: File;
  type?: string;
}

export type PlanType =
  | "erp-j"
  | "erp-l"
  | "erp-m"
  | "erp-n"
  | "erp-o"
  | "erp-p"
  | "erp-r"
  | "erp-s"
  | "erp-t"
  | "erp-u"
  | "erp-v"
  | "erp-w"
  | "erp-x"
  | "erp-y"
  | "erp-pa"
  | "erp-ps"
  | "non-erp"
  | "custom";

export type ContactPlan = {
  saas_plan_id: string;
  contact_id: Identifier;
  name: string;
  description: string | null;
  plan_type: PlanType | string;
  status: string;
  completion_score: number | null;
  thumbnail_url: string | null;
  preview_url: string | null;
  format: string;
  orientation: string;
  created_at: string;
  updated_at: string;
} & Pick<RaRecord, "id">;

export type AttachmentNote = RAFile;

export interface LabeledValue {
  value: string;
  label: string;
}

export type DealStage = LabeledValue;

export type DevTaskStatus = LabeledValue;

export interface DevTaskPriority extends LabeledValue {
  icon: string;
  colorClass: string;
}

export type DevTask = {
  title: string;
  description: string | null;
  status: string;
  priority: string;
  index: number;
  assignee_id: Identifier | null;
  assignee_ids: Identifier[];
  due_date: string | null;
  label_ids: Identifier[];
  contact_id: Identifier | null;
  company_id: Identifier | null;
  deal_id: Identifier | null;
  archived_at: string | null;
  created_at: string;
  updated_at: string;
} & Pick<RaRecord, "id">;

export type DevTaskLabel = {
  name: string;
  color: string;
  created_at: string;
} & Pick<RaRecord, "id">;

export interface NoteStatus extends LabeledValue {
  color: string;
}

export interface ContactGender {
  value: string;
  label: string;
  icon: ComponentType<{ className?: string }>;
}

export type Payment = {
  stripe_event_id: string;
  stripe_object_id: string;
  stripe_customer_id: string | null;
  company_id: Identifier | null;
  deal_id: Identifier | null;
  type: string;
  status: string | null;
  amount: number;
  amount_refunded: number;
  currency: string;
  description: string | null;
  invoice_number: string | null;
  hosted_invoice_url: string | null;
  receipt_url: string | null;
  occurred_at: string;
  metadata: Record<string, unknown>;
  created_at: string;
} & Pick<RaRecord, "id">;

export type Subscription = {
  stripe_subscription_id: string;
  stripe_customer_id: string;
  company_id: Identifier | null;
  status: string;
  product_name: string | null;
  amount: number | null;
  currency: string | null;
  recurring_interval: string | null;
  current_period_start: string | null;
  current_period_end: string | null;
  cancel_at_period_end: boolean;
  canceled_at: string | null;
  started_at: string | null;
  metadata: Record<string, unknown>;
  updated_at: string;
  created_at: string;
} & Pick<RaRecord, "id">;

export const COMPANY_CREATED = "company.created" as const;
export const CONTACT_CREATED = "contact.created" as const;
export const CONTACT_NOTE_CREATED = "contactNote.created" as const;
export const DEAL_CREATED = "deal.created" as const;
export const DEAL_NOTE_CREATED = "dealNote.created" as const;

import {
  useCreate,
  useDelete,
  useGetList,
  useGetIdentity,
  useNotify,
  useRefresh,
} from "ra-core";
import { useState, useCallback } from "react";
import {
  Video,
  Trash2,
  ExternalLink,
  Plus,
  ChevronDown,
  ChevronUp,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";

export type VideoConference = {
  id: number;
  contact_id: number | null;
  company_id: number | null;
  title: string;
  url: string;
  transcription_url: string | null;
  transcription: string | null;
  recorded_at: string | null;
  duration_minutes: number | null;
  provider: string;
  notes: string | null;
  sales_id: number | null;
  created_at: string;
};

const PROVIDERS = [
  { value: "zoom", label: "Zoom" },
  { value: "meet", label: "Google Meet" },
  { value: "teams", label: "Microsoft Teams" },
  { value: "loom", label: "Loom" },
  { value: "whereby", label: "Whereby" },
  { value: "other", label: "Autre" },
];

function providerLabel(value: string): string {
  return PROVIDERS.find((p) => p.value === value)?.label ?? value;
}

function formatDate(iso?: string | null): string {
  if (!iso) return "";
  return new Date(iso).toLocaleDateString(undefined, {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
}

function VideoConferenceItem({
  conference,
  showContactName,
}: {
  conference: VideoConference;
  showContactName?: string;
}) {
  const [expanded, setExpanded] = useState(false);
  const [deleteOne, { isPending: isDeleting }] = useDelete();
  const notify = useNotify();
  const refresh = useRefresh();

  const handleDelete = useCallback(() => {
    if (
      !window.confirm(
        "Supprimer cette visioconférence ? Le lien et la transcription seront définitivement effacés.",
      )
    ) {
      return;
    }
    deleteOne(
      "video_conferences",
      { id: conference.id },
      {
        onSuccess: () => {
          notify("Visio supprimée", { type: "success" });
          refresh();
        },
        onError: () => notify("Suppression impossible", { type: "error" }),
      },
    );
  }, [deleteOne, conference.id, notify, refresh]);

  return (
    <div className="border rounded-lg p-3">
      <div className="flex items-center gap-3">
        <Video className="h-4 w-4 text-muted-foreground shrink-0" />
        <div
          className="flex-1 min-w-0 cursor-pointer"
          onClick={() => setExpanded(!expanded)}
        >
          <div className="text-sm font-medium truncate">
            {showContactName ? `${showContactName} · ` : ""}
            {conference.title || providerLabel(conference.provider)}
          </div>
          <div className="text-xs text-muted-foreground flex items-center gap-2 flex-wrap">
            <span>{providerLabel(conference.provider)}</span>
            {conference.recorded_at && (
              <>
                <span>·</span>
                <span>{formatDate(conference.recorded_at)}</span>
              </>
            )}
            {conference.duration_minutes != null && (
              <>
                <span>·</span>
                <span>{conference.duration_minutes} min</span>
              </>
            )}
          </div>
        </div>
        <a
          href={conference.url}
          target="_blank"
          rel="noopener noreferrer"
          className="shrink-0"
          onClick={(e) => e.stopPropagation()}
        >
          <Button
            variant="ghost"
            size="icon"
            className="h-7 w-7 text-muted-foreground hover:text-blue-500"
            aria-label="Ouvrir la visio"
            title="Ouvrir la visio"
          >
            <ExternalLink className="h-3.5 w-3.5" />
          </Button>
        </a>
        <Button
          variant="ghost"
          size="icon"
          className="h-7 w-7 text-muted-foreground hover:text-red-500"
          aria-label="Supprimer"
          onClick={handleDelete}
          disabled={isDeleting}
        >
          <Trash2 className="h-3.5 w-3.5" />
        </Button>
        <div className="cursor-pointer" onClick={() => setExpanded(!expanded)}>
          {expanded ? (
            <ChevronUp className="h-4 w-4" />
          ) : (
            <ChevronDown className="h-4 w-4" />
          )}
        </div>
      </div>

      {expanded && (
        <div className="mt-3 space-y-3 text-sm">
          {conference.transcription_url && (
            <div>
              <span className="text-xs text-muted-foreground block mb-1">
                Lien transcription
              </span>
              <a
                href={conference.transcription_url}
                target="_blank"
                rel="noopener noreferrer"
                className="text-blue-500 underline break-all"
              >
                {conference.transcription_url}
              </a>
            </div>
          )}
          {conference.transcription && (
            <div className="bg-muted rounded-md p-3">
              <div className="text-xs font-medium text-muted-foreground mb-1">
                Transcription
              </div>
              <p className="whitespace-pre-wrap">{conference.transcription}</p>
            </div>
          )}
          {conference.notes && (
            <div>
              <span className="text-xs text-muted-foreground block mb-1">
                Notes
              </span>
              <p className="whitespace-pre-wrap">{conference.notes}</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

type AddFormProps = {
  defaultContactId?: number | null;
  defaultCompanyId?: number | null;
  onClose: () => void;
};

function AddVideoConferenceForm({
  defaultContactId,
  defaultCompanyId,
  onClose,
}: AddFormProps) {
  const { identity } = useGetIdentity();
  const notify = useNotify();
  const refresh = useRefresh();
  const [create, { isPending }] = useCreate();

  const [title, setTitle] = useState("");
  const [url, setUrl] = useState("");
  const [provider, setProvider] = useState("zoom");
  const [recordedAt, setRecordedAt] = useState(
    new Date().toISOString().slice(0, 16),
  );
  const [durationMinutes, setDurationMinutes] = useState<string>("");
  const [transcriptionUrl, setTranscriptionUrl] = useState("");
  const [transcription, setTranscription] = useState("");
  const [notes, setNotes] = useState("");

  const handleSubmit = useCallback(() => {
    if (!url.trim()) {
      notify("Le lien de la visio est requis", { type: "error" });
      return;
    }
    create(
      "video_conferences",
      {
        data: {
          contact_id: defaultContactId ?? null,
          company_id: defaultCompanyId ?? null,
          title: title.trim(),
          url: url.trim(),
          provider,
          recorded_at: recordedAt ? new Date(recordedAt).toISOString() : null,
          duration_minutes: durationMinutes ? Number(durationMinutes) : null,
          transcription_url: transcriptionUrl.trim() || null,
          transcription: transcription.trim() || null,
          notes: notes.trim() || null,
          sales_id: identity?.id ?? null,
        },
      },
      {
        onSuccess: () => {
          notify("Visio enregistrée", { type: "success" });
          refresh();
          onClose();
        },
        onError: (e) =>
          notify(`Échec: ${e instanceof Error ? e.message : String(e)}`, {
            type: "error",
          }),
      },
    );
  }, [
    create,
    title,
    url,
    provider,
    recordedAt,
    durationMinutes,
    transcriptionUrl,
    transcription,
    notes,
    defaultContactId,
    defaultCompanyId,
    identity,
    notify,
    refresh,
    onClose,
  ]);

  return (
    <div className="space-y-3">
      <div>
        <Label htmlFor="vc-title">Titre</Label>
        <Input
          id="vc-title"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          placeholder="Démo produit, découverte, etc."
        />
      </div>
      <div>
        <Label htmlFor="vc-url">Lien vers la visio / l'enregistrement *</Label>
        <Input
          id="vc-url"
          value={url}
          onChange={(e) => setUrl(e.target.value)}
          placeholder="https://..."
        />
      </div>
      <div className="grid grid-cols-2 gap-3">
        <div>
          <Label htmlFor="vc-provider">Plateforme</Label>
          <Select value={provider} onValueChange={setProvider}>
            <SelectTrigger id="vc-provider">
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              {PROVIDERS.map((p) => (
                <SelectItem key={p.value} value={p.value}>
                  {p.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div>
          <Label htmlFor="vc-duration">Durée (min)</Label>
          <Input
            id="vc-duration"
            type="number"
            value={durationMinutes}
            onChange={(e) => setDurationMinutes(e.target.value)}
            placeholder="30"
          />
        </div>
      </div>
      <div>
        <Label htmlFor="vc-recorded">Date</Label>
        <Input
          id="vc-recorded"
          type="datetime-local"
          value={recordedAt}
          onChange={(e) => setRecordedAt(e.target.value)}
        />
      </div>
      <div>
        <Label htmlFor="vc-transcription-url">Lien transcription</Label>
        <Input
          id="vc-transcription-url"
          value={transcriptionUrl}
          onChange={(e) => setTranscriptionUrl(e.target.value)}
          placeholder="Lien vers la page transcription (optionnel)"
        />
      </div>
      <div>
        <Label htmlFor="vc-transcription">Transcription collée</Label>
        <Textarea
          id="vc-transcription"
          value={transcription}
          onChange={(e) => setTranscription(e.target.value)}
          rows={4}
          placeholder="Copier-coller le texte de la transcription (optionnel)"
        />
      </div>
      <div>
        <Label htmlFor="vc-notes">Notes</Label>
        <Textarea
          id="vc-notes"
          value={notes}
          onChange={(e) => setNotes(e.target.value)}
          rows={2}
        />
      </div>
      <div className="flex justify-end gap-2 pt-2">
        <Button variant="outline" onClick={onClose} disabled={isPending}>
          Annuler
        </Button>
        <Button onClick={handleSubmit} disabled={isPending}>
          {isPending ? "Enregistrement..." : "Enregistrer"}
        </Button>
      </div>
    </div>
  );
}

export function AddVideoConferenceButton({
  contactId,
  companyId,
}: {
  contactId?: number | null;
  companyId?: number | null;
}) {
  const [open, setOpen] = useState(false);
  return (
    <>
      <Button
        variant="outline"
        size="sm"
        className="h-7"
        onClick={() => setOpen(true)}
      >
        <Plus className="h-3.5 w-3.5 mr-1" />
        Ajouter une visio
      </Button>
      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Nouvelle visioconférence</DialogTitle>
          </DialogHeader>
          <AddVideoConferenceForm
            defaultContactId={contactId ?? null}
            defaultCompanyId={companyId ?? null}
            onClose={() => setOpen(false)}
          />
        </DialogContent>
      </Dialog>
    </>
  );
}

export function ContactVideoConferencesList({
  contactId,
}: {
  contactId: number;
}) {
  const { data: conferences, isPending } = useGetList<VideoConference>(
    "video_conferences",
    {
      filter: { contact_id: contactId },
      sort: { field: "recorded_at", order: "DESC" },
      pagination: { page: 1, perPage: 50 },
    },
  );

  return (
    <div className="flex flex-col gap-2">
      {isPending ? null : !conferences?.length ? (
        <p className="text-xs text-muted-foreground italic">
          Aucune visio pour l'instant
        </p>
      ) : (
        conferences.map((c) => (
          <VideoConferenceItem key={c.id} conference={c} />
        ))
      )}
      <div className="mt-1">
        <AddVideoConferenceButton contactId={contactId} />
      </div>
    </div>
  );
}

export function CompanyVideoConferencesList({
  companyId,
}: {
  companyId: number;
}) {
  // Fetch company-level + contact-level visios
  const { data: companyVisios } = useGetList<VideoConference>(
    "video_conferences",
    {
      filter: { company_id: companyId },
      sort: { field: "recorded_at", order: "DESC" },
      pagination: { page: 1, perPage: 200 },
    },
  );

  // Fetch all contacts of this company, then their visios
  const { data: contacts } = useGetList<{
    id: number;
