import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";

export type MarkDoneKind = "task" | "appointment" | "devtask";

interface Props {
  open: boolean;
  onOpenChange: (o: boolean) => void;
  kind: MarkDoneKind;
  id: number;
  contactId?: number | null;
  title?: string;
  onDone?: () => void;
}

export function MarkDoneDialog({
  open,
  onOpenChange,
  kind,
  id,
  contactId,
  title,
  onDone,
}: Props) {
  const notify = useNotify();
  const refresh = useRefresh();
  const { identity } = useGetIdentity();
  const [update] = useUpdate();
  const [create] = useCreate();

  const [comment, setComment] = useState("");
  const [followUp, setFollowUp] = useState(false);
  const [followUpText, setFollowUpText] = useState("");
  const [followUpDate, setFollowUpDate] = useState(() => {
    const d = new Date();
    d.setDate(d.getDate() + 3);
    return d.toISOString().slice(0, 10);
  });
  const [saving, setSaving] = useState(false);

  const resourceForKind = {
    task: "tasks",
    appointment: "appointments",
    devtask: "dev_tasks",
  }[kind];

  const handleSave = useCallback(async () => {
    setSaving(true);
    try {
      // 1. Mark the entity as done
      const now = new Date().toISOString();
      const data: Record<string, unknown> =
        kind === "task"
          ? { done_date: now }
          : kind === "appointment"
            ? { status: "completed" }
            : { status: "done" };

      await new Promise<void>((resolve, reject) => {
        update(
          resourceForKind,
          { id, data, previousData: {} },
          {
            onSuccess: () => resolve(),
            onError: (e) => reject(e),
          },
        );
      });

      // 2. Record the comment as a contact_note if we have a contact_id and a comment
      if (comment.trim() && contactId) {
        const typeLabel =
          kind === "task"
            ? "Tâche terminée"
            : kind === "appointment"
              ? "Rendez-vous terminé"
              : "Ticket dev terminé";
        const labelTitle = title ? ` — ${title}` : "";
        await new Promise<void>((resolve) => {
          create(
            "contact_notes",
            {
              data: {
                contact_id: contactId,
                text: `✅ ${typeLabel}${labelTitle}\n\n${comment.trim()}`,
                date: now,
                sales_id: identity?.id,
                status: "follow-up",
              },
            },
            {
              onSuccess: () => resolve(),
              onError: () => resolve(), // non blocking
            },
          );
        });
      }

      // 3. Optionally create a follow-up task
      if (followUp && followUpText.trim()) {
        await new Promise<void>((resolve) => {
          create(
            "tasks",
            {
              data: {
                type: "follow-up",
                text: followUpText.trim(),
                due_date: followUpDate
                  ? new Date(followUpDate).toISOString()
                  : now,
                contact_id: contactId ?? null,
                sales_id: identity?.id,
              },
            },
            {
              onSuccess: () => resolve(),
              onError: () => resolve(),
            },
          );
        });
      }

      notify("Terminé ✓", { type: "success" });
      refresh();
      onOpenChange(false);
      onDone?.();
    } catch (e) {
      notify(
        `Impossible de clôturer: ${e instanceof Error ? e.message : String(e)}`,
        { type: "error" },
      );
    } finally {
      setSaving(false);
    }
  }, [
    kind,
    id,
    contactId,
    title,
    comment,
    followUp,
    followUpText,
    followUpDate,
    update,
    create,
    notify,
    refresh,
    onOpenChange,
    onDone,
    resourceForKind,
    identity,
  ]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <CheckCircle2 className="h-5 w-5 text-emerald-500" />
            Marquer comme terminé
          </DialogTitle>
          {title && <DialogDescription>{title}</DialogDescription>}
        </DialogHeader>
        <div className="space-y-3">
          <div>
            <Label htmlFor="done-comment">Commentaire (optionnel)</Label>
            <Textarea
              id="done-comment"
              rows={3}
              placeholder="Qu'est-ce qui a été fait ? Résultat ? Ressenti ?"
              value={comment}
              onChange={(e) => setComment(e.target.value)}
            />
            {contactId && (
              <p className="text-xs text-muted-foreground mt-1">
                Le commentaire sera ajouté en note sur la fiche contact.
              </p>
            )}
          </div>

          <div className="border-t pt-3">
            <label className="flex items-center gap-2 cursor-pointer text-sm">
              <input
                type="checkbox"
                checked={followUp}
                onChange={(e) => setFollowUp(e.target.checked)}
              />
              Créer une tâche de suivi
            </label>
            {followUp && (
              <div className="mt-2 space-y-2 pl-6">
                <div>
                  <Label htmlFor="followup-text" className="text-xs">
                    À faire
                  </Label>
                  <Input
                    id="followup-text"
                    placeholder="Relancer, envoyer le devis, etc."
                    value={followUpText}
                    onChange={(e) => setFollowUpText(e.target.value)}
                  />
                </div>
                <div>
                  <Label htmlFor="followup-date" className="text-xs">
                    Échéance
                  </Label>
                  <Input
                    id="followup-date"
                    type="date"
                    value={followUpDate}
                    onChange={(e) => setFollowUpDate(e.target.value)}
                  />
                </div>
              </div>
            )}
          </div>
        </div>
        <DialogFooter>
          <Button
            variant="outline"
            onClick={() => onOpenChange(false)}
            disabled={saving}
          >
            Annuler
          </Button>
          <Button onClick={handleSave} disabled={saving}>
            {saving ? (
              <>
                <Loader2 className="h-4 w-4 mr-1 animate-spin" />
                Enregistrement...
              </>
            ) : (
              <>
                <CheckCircle2 className="h-4 w-4 mr-1" /> Terminer
              </>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import * as React from "react";
import { useEffect, useRef } from "react";
import {
  useInfinitePaginationContext,
  useListContext,
  useEvent,
  useTranslate,
} from "ra-core";
import { Item, ItemContent, ItemMedia, ItemTitle } from "@/components/ui/item";
import { Spinner } from "@/components/admin/spinner";

/**
 * A pagination component that loads more results when the user scrolls to the bottom of the list.
 *
 * Used as the default pagination component in the <InfiniteList> component.
 *
 * @example
 * import { InfiniteList, InfinitePagination, Datagrid, TextField } from 'react-admin';
 *
 * const PostList = () => (
 *    <InfiniteList pagination={<InfinitePagination sx={{ py: 5 }} />}>
 *       <Datagrid>
 *          <TextField source="id" />
 *         <TextField source="title" />
 *      </Datagrid>
 *   </InfiniteList>
 * );
 */
export const InfinitePagination = ({
  offline = null,
  options = defaultOptions,
}: InfinitePaginationProps) => {
  const translate = useTranslate();
  const { isPaused, isPending } = useListContext();
  const { fetchNextPage, hasNextPage, isFetchingNextPage } =
    useInfinitePaginationContext();

  if (!fetchNextPage) {
    throw new Error(
      "InfinitePagination must be used inside an InfinitePaginationContext, usually created by <InfiniteList>. You cannot use it as child of a <List> component.",
    );
  }

  const [hasRequestedNextPage, setHasRequestedNextPage] = React.useState(false);
  const observerElem = useRef(null);
  const handleObserver = useEvent<[IntersectionObserverEntry[]], void>(
    (entries) => {
      const [target] = entries;
      if (target.isIntersecting && hasNextPage && !isFetchingNextPage) {
        setHasRequestedNextPage(true);
        fetchNextPage();
      }
    },
  );

  useEffect(() => {
    // Whenever the query is unpaused, reset the requested next page state
    if (!isPaused) {
      setHasRequestedNextPage(false);
    }
  }, [isPaused]);

  useEffect(() => {
    const element = observerElem.current;
    if (!element) return;
    const observer = new IntersectionObserver(handleObserver, options);
    observer.observe(element);
    return () => observer.unobserve(element);
  }, [
    fetchNextPage,
    hasNextPage,
    handleObserver,
    options,
    isPending,
    isFetchingNextPage,
  ]);

  if (isPending) return null;

  const showOffline =
    isPaused &&
    hasNextPage &&
    hasRequestedNextPage &&
    offline !== false &&
    offline !== undefined;

  return (
    <div ref={observerElem} className="py-2 text-center">
      {showOffline ? (
        offline
      ) : isFetchingNextPage && hasNextPage ? (
        <Item variant="default">
          <ItemMedia>
            <Spinner />
          </ItemMedia>
          <ItemContent>
            <ItemTitle className="line-clamp-1">
              {translate("crm.common.loading")}
            </ItemTitle>
          </ItemContent>
        </Item>
      ) : (
        <Item variant="default">
          <ItemContent>
            <ItemTitle className="line-clamp-1">&nbsp;</ItemTitle>
          </ItemContent>
        </Item>
      )}
    </div>
  );
};

const defaultOptions = { threshold: 0 };

export interface InfinitePaginationProps {
  offline?: React.ReactNode;
  options?: IntersectionObserverInit;
}

