  const handleSelect = (m: EmailMessage) => {
    setSelectedId(m.id);
    if (!m.is_read) {
      update(
        "email_messages",
        { id: m.id, data: { is_read: true }, previousData: m },
        {
          onSuccess: () => refresh(),
        },
      );
    }
  };

  const toggleRead = (m: EmailMessage) => {
    update(
      "email_messages",
      { id: m.id, data: { is_read: !m.is_read }, previousData: m },
