        ) : null}
      </div>
      <Card className="p-4">
        {isPending ? (
          <p className="text-sm text-muted-foreground">Chargement…</p>
        ) : list.length === 0 ? (
          <p className="text-sm text-muted-foreground">
            Aucun email non lu pour le moment.
          </p>
        ) : (
          <>
            <ul className="flex flex-col divide-y">
