export const MyDayPage = () => {
  const { identity } = useGetIdentity();
  const startOfDay = new Date();
  startOfDay.setHours(0, 0, 0, 0);

  const { data: tasks } = useGetList<Task>(
    "tasks",
    {
      pagination: { page: 1, perPage: 100 },
      sort: { field: "due_date", order: "ASC" },
      filter: identity?.id
        ? { sales_id: identity.id, "done_date@is": null }
        : { "done_date@is": null },
    },
    { enabled: !!identity },
  );

  const { data: appointments } = useGetList<Appointment>("appointments", {
    pagination: { page: 1, perPage: 50 },
    sort: { field: "start_at", order: "ASC" },
    filter: identity?.id
      ? {
          sales_id: identity.id,
          "start_at@gte": startOfDay.toISOString(),
          "start_at@lt": new Date(
            startOfDay.getTime() + 24 * 60 * 60 * 1000,
          ).toISOString(),
        }
      : {},
  });

  const { data: myDevTasks } = useGetList<DevTask>(
    "dev_tasks",
    {
      pagination: { page: 1, perPage: 50 },
      sort: { field: "due_date", order: "ASC" },
      filter: {
        "assignee_ids@cs": identity ? `{${identity.id}}` : "{0}",
        "archived_at@is": null,
      },
    },
    { enabled: !!identity },
  );

  const { data: deals } = useGetList<Deal>("deals", {
    pagination: { page: 1, perPage: 200 },
    filter: { "pipeline_status@eq": "in-progress" },
  });

  const { data: contacts } = useGetList<Contact>("contacts", {
    pagination: { page: 1, perPage: 200 },
    sort: { field: "last_seen", order: "DESC" },
    filter: identity?.id ? { sales_id: identity.id } : {},
  });

  const unreadSummary = useGetList<{ total_unread: number }>(
    "unread_emails_summary",
    { pagination: { page: 1, perPage: 10 } },
  );
  const unreadCount =
    unreadSummary.data?.reduce((s, r) => s + (r.total_unread ?? 0), 0) ?? 0;

  const todayEnd = new Date(startOfDay);
  todayEnd.setDate(todayEnd.getDate() + 1);

  const overdue = (tasks ?? []).filter(
    (t) => new Date(t.due_date) < startOfDay,
  );
  const todayTasks = (tasks ?? []).filter(
    (t) =>
      new Date(t.due_date) >= startOfDay && new Date(t.due_date) < todayEnd,
  );

  const staleDeals = (deals ?? []).filter((d) => {
    const ref = new Date(d.updated_at ?? d.created_at).getTime();
    return Date.now() - ref >= 7 * 24 * 60 * 60 * 1000;
  });

  const todayDevTasks = (myDevTasks ?? []).filter((t) => {
    if (!t.due_date) return false;
    const d = new Date(t.due_date);
    return d >= startOfDay && d < todayEnd;
  });
  const overdueDevTasks = (myDevTasks ?? []).filter((t) => {
    if (!t.due_date) return false;
    return new Date(t.due_date) < startOfDay;
  });

  // Build timeline: overdue first, then today by time
  const items: TimelineItem[] = [
    ...overdue.slice(0, 5).map<TimelineItem>((t) => ({
      kind: "task",
      tone: "red",
      time: new Date(t.due_date).toLocaleDateString("fr-FR", {
        day: "2-digit",
        month: "2-digit",
      }),
      title: `⚠ ${t.text}`,
      meta: "En retard",
      href: t.contact_id ? `/contacts/${t.contact_id}/show` : "/tasks",
      doneTarget: {
        kind: "task",
        id: Number(t.id),
        contactId: t.contact_id ?? null,
      },
    })),
    ...overdueDevTasks.slice(0, 5).map<TimelineItem>((t) => ({
      kind: "task",
      tone: "red",
      time: new Date(t.due_date!).toLocaleDateString("fr-FR", {
        day: "2-digit",
        month: "2-digit",
      }),
      title: `🛠 ${t.title}`,
      meta: "Ticket dev en retard",
      href: `/dev_tasks/${t.id}/show`,
      doneTarget: {
        kind: "devtask",
        id: Number(t.id),
        contactId: (t.contact_id as number | null) ?? null,
      },
    })),
    ...(appointments ?? []).map<TimelineItem>((a) => ({
      kind: "meeting",
      tone: "cool",
      time: new Date(a.start_at).toLocaleTimeString("fr-FR", {
        hour: "2-digit",
        minute: "2-digit",
      }),
      title: `📅 ${a.title}`,
      meta: a.location ? `RDV · ${a.location}` : "Rendez-vous",
      href: "/appointments",
      doneTarget:
        a.status !== "completed"
          ? {
              kind: "appointment",
              id: Number(a.id),
              contactId: a.contact_id ?? null,
            }
          : undefined,
    })),
    ...todayTasks.map<TimelineItem>((t) => ({
      kind: "task",
      tone: "accent",
      time: new Date(t.due_date).toLocaleTimeString("fr-FR", {
        hour: "2-digit",
        minute: "2-digit",
      }),
      title: t.text,
      meta: t.type || "Tâche",
      href: t.contact_id ? `/contacts/${t.contact_id}/show` : "/tasks",
      doneTarget: {
        kind: "task",
        id: Number(t.id),
        contactId: t.contact_id ?? null,
      },
    })),
    ...todayDevTasks.map<TimelineItem>((t) => ({
      kind: "task",
      tone: "accent",
      time: "Aujourd'hui",
      title: `🛠 ${t.title}`,
      meta: "Ticket dev",
      href: `/dev_tasks/${t.id}/show`,
      doneTarget: {
        kind: "devtask",
        id: Number(t.id),
        contactId: (t.contact_id as number | null) ?? null,
      },
    })),
  ];

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-5 max-w-6xl">
      <div className="lg:col-span-2 space-y-4">
        <PrioritiesCard
          overdueCount={overdue.length}
          todayCount={todayTasks.length}
          unreadCount={unreadCount}
          staleCount={staleDeals.length}
        />
        <Timeline items={items} />
      </div>

      <div className="space-y-4">
        <StaleDealsCard deals={deals ?? []} />
        <FollowUpContactsCard contacts={contacts ?? []} />
      </div>
    </div>
  );
};

