import { type Identifier, useNotify, useDelete, useRefresh } from "ra-core";
import { Trash2 } from "lucide-react";
import { Button } from "@/components/ui/button";

import { EditSheet } from "../misc/EditSheet";
import { AppointmentInputs } from "./AppointmentInputs";

export interface AppointmentEditSheetProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  appointmentId: Identifier;
}

export const AppointmentEditSheet = ({
  open,
  onOpenChange,
  appointmentId,
}: AppointmentEditSheetProps) => {
  const notify = useNotify();
  const refresh = useRefresh();
  const [deleteOne, { isPending: isDeleting }] = useDelete();

  const handleSuccess = () => {
    notify("Rendez-vous mis à jour", { type: "success" });
    refresh();
    onOpenChange(false);
  };

  const handleDelete = () => {
    if (!confirm("Supprimer ce rendez-vous ?")) return;
    deleteOne(
      "appointments",
      { id: appointmentId },
      {
        onSuccess: () => {
          notify("Rendez-vous supprimé", { type: "success" });
          refresh();
          onOpenChange(false);
        },
        onError: () => {
          notify("Échec de la suppression", { type: "error" });
        },
      },
    );
  };

  return (
    <EditSheet
      resource="appointments"
      id={appointmentId}
      title={
        <span className="text-xl font-semibold truncate pr-10">
          Modifier le rendez-vous
        </span>
      }
      redirect={false}
      mutationMode="pessimistic"
      mutationOptions={{
        onSuccess: handleSuccess,
      }}
      open={open}
      onOpenChange={onOpenChange}
      headerActions={
        <Button
          variant="ghost"
          size="icon"
          onClick={handleDelete}
          disabled={isDeleting}
          title="Supprimer"
        >
          <Trash2 className="h-4 w-4 text-destructive" />
        </Button>
      }
    >
      <AppointmentInputs selectContact />
    </EditSheet>
  );
};

import { type Identifier, useGetIdentity, useNotify } from "ra-core";
import { useQueryClient } from "@tanstack/react-query";
import { CreateSheet } from "../misc/CreateSheet";
import { AppointmentInputs } from "./AppointmentInputs";

export interface AppointmentCreateSheetProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  contact_id?: Identifier | null;
  defaultStart?: string;
  defaultEnd?: string;
  defaultSource?: "manual" | "phone_call" | "email_campaign";
}

export const AppointmentCreateSheet = ({
  open,
  onOpenChange,
  contact_id,
  defaultStart,
  defaultEnd,
  defaultSource = "manual",
}: AppointmentCreateSheetProps) => {
  const { identity } = useGetIdentity();
  const notify = useNotify();
  const queryClient = useQueryClient();

  if (!identity) return null;

  const now = new Date();
  const oneHourLater = new Date(now.getTime() + 60 * 60 * 1000);

  const handleSuccess = () => {
    queryClient.invalidateQueries({ queryKey: ["appointments"] });
    queryClient.invalidateQueries({ queryKey: ["contacts"] });
    queryClient.invalidateQueries({ queryKey: ["contacts_summary"] });
    notify("Rendez-vous créé", { type: "success" });
    onOpenChange(false);
  };

  return (
    <CreateSheet
      resource="appointments"
      title={
        <span className="text-xl font-semibold truncate pr-10">
          Nouveau rendez-vous
        </span>
      }
      redirect={false}
      record={{
        title: "",
        contact_id: contact_id ?? null,
        start_at: defaultStart ?? now.toISOString(),
        end_at: defaultEnd ?? oneHourLater.toISOString(),
        source: defaultSource,
        status: "scheduled",
        sales_id: identity.id,
      }}
      mutationOptions={{
        onSuccess: handleSuccess,
      }}
      open={open}
      onOpenChange={onOpenChange}
    >
      <AppointmentInputs selectContact={contact_id == null} />
    </CreateSheet>
  );
};

